15	/**
16	 * Apache FESOD event listener for batch reading Excel data without model mapping.
17	 * Caches data in memory and logs progress during parsing.
18	 *
19	 * @author summer
20	 * @version 1.00
21	 * @date 2026/3/1
22	 */
23	@Slf4j
24	public class NoModelDataListener extends AnalysisEventListener<Map<Integer, Object>> {
25	
26	    private static final int BATCH_COUNT = 500000;
27	    @Getter
28	    private List<Map<Integer, Object>> cachedDataList = ListUtils.newArrayListWithExpectedSize(BATCH_COUNT);
29	    private boolean usedDataBase;
30	
31	    /**
32	     * Clears the cached data list and reinitializes it for the next batch of data.
33	     */
34	    public void clear() {
35	        cachedDataList = ListUtils.newArrayListWithExpectedSize(BATCH_COUNT);
36	    }
37	
38	    @Override
39	    public void invoke(Map<Integer, Object> data, AnalysisContext context) {
40	        log.debug("Parsed one data row: {}", JSON.toJSONString(data));
41	        usedDataBase = false;
42	        cachedDataList.add(data);
43	        if (cachedDataList.size() >= BATCH_COUNT) {
44	            saveData();
45	            cachedDataList = ListUtils.newArrayListWithExpectedSize(BATCH_COUNT);
46	        }
47	    }
48	
49	    @Override
50	    public void doAfterAllAnalysed(AnalysisContext context) {
51	        if (usedDataBase) {
52	            saveData();
53	            usedDataBase = false;
54	        }
55	        log.info("All data parsing completed!");
56	    }
57	
58	    /**
59	     * Saves data to the database (placeholder implementation).
60	     */
61	    private void saveData() {
62	        log.info("{} rows of data, starting to save to database!", cachedDataList.size());
63	        usedDataBase = true;
64	        log.info("Database save successful!");
65	    }
66	}

1	package fan.summer.utils;
2	
3	import org.apache.poi.ss.usermodel.*;
4	import org.apache.poi.ss.util.CellRangeAddress;
5	import org.apache.poi.xssf.usermodel.XSSFWorkbook;
6	import org.slf4j.Logger;
7	import org.slf4j.LoggerFactory;
8	
9	import java.io.File;
10	import java.io.FileInputStream;
11	import java.io.FileOutputStream;
12	import java.io.IOException;
13	import java.util.HashMap;
14	import java.util.List;
15	import java.util.Map;
16	import java.util.Set;
17	
18	/**
19	 * Utility class for Excel file operations.
20	 * Provides methods for appending sheets and data rows to Excel files.
21	 *
22	 * @author summer
23	 * @version 1.00
24	 * @date 2026/3/4
25	 */
26	public class ExcelUtil {
27	    private static final Logger logger = LoggerFactory.getLogger(ExcelUtil.class);
28	
29	    private static final Set<String> INVALID_VALUES = Set.of(
30	            "NA", "N/A", "NULL", "NIL", "NONE", "NAN",
31	            "#N/A", "#NULL!", "#REF!", "#DIV/0!", "#VALUE!", "#NAME?", "#NUM!", "#ERROR!",
32	            "-", "--", "—", "N.A.", "N.A"
33	    );
34	
35	    /**
36	     * Appends rows from 0 to endRowIndex of the specified sheet (by name) in source file to target file.
37	     * Creates target file if it doesn't exist; appends to existing sheet without overwriting.
38	     *
39	     * @param sourceFilePath source file path
40	     * @param targetFilePath target file path (creates if not exists)
41	     * @param sheetName      sheet name to copy
42	     * @param endRowIndex    end row index (0-based, inclusive)
43	     */
44	    public static void appendSheet(String sourceFilePath, String targetFilePath,
45	                                   String sheetName, int endRowIndex) throws IOException {
46	        if (endRowIndex < 0) throw new IllegalArgumentException("endRowIndex cannot be negative");
47	
48	        // 1. Read source file and locate sheet
49	        try (FileInputStream srcFis = new FileInputStream(sourceFilePath);
50	             Workbook sourceWorkbook = WorkbookFactory.create(srcFis)) {
51	
52	            Sheet sourceSheet = sourceWorkbook.getSheet(sheetName);
53	            if (sourceSheet == null) {
54	                throw new IllegalArgumentException("Sheet not found: " + sheetName
55	                        + ", available sheets: " + getSheetNames(sourceWorkbook));
56	            }
57	
58	            // 2. Load or create target workbook
59	            Workbook targetWorkbook = loadOrCreate(targetFilePath);
60	
61	            // 3. Target file must not have a sheet with the same name
62	            if (targetWorkbook.getSheet(sheetName) != null) {
63	                targetWorkbook.close();
64	                throw new IllegalArgumentException("Target file already has sheet: " + sheetName);
65	            }
66	
67	            // 4. Append sheet
68	            copySheetRows(sourceSheet, targetWorkbook, sheetName, endRowIndex);
69	
70	            // 5. Write back to target file
71	            try (FileOutputStream fos = new FileOutputStream(targetFilePath)) {
72	                targetWorkbook.write(fos);
73	            }
74	            targetWorkbook.close();
75	
76	            logger.debug("Sheet appended | sheet={}, rows=0-{}, target={}", sheetName, endRowIndex, targetFilePath);
77	        }
78	    }
79	
80	    /**
81	     * Appends rows from 0 to endRowIndex of the specified sheet (by index) in source file to target file.
82	     *
83	     * @param sourceFilePath source file path
84	     * @param targetFilePath target file path (creates if not exists)
85	     * @param sheetIndex     sheet index (0-based)
86	     * @param endRowIndex    end row index (0-based, inclusive)
87	     */
88	    public static void appendSheet(String sourceFilePath, String targetFilePath,
89	                                   int sheetIndex, int endRowIndex) throws IOException {
90	        if (endRowIndex < 0) throw new IllegalArgumentException("endRowIndex cannot be negative");
91	
92	        try (FileInputStream srcFis = new FileInputStream(sourceFilePath);
93	             Workbook sourceWorkbook = WorkbookFactory.create(srcFis)) {
94	
95	            if (sheetIndex < 0 || sheetIndex >= sourceWorkbook.getNumberOfSheets()) {
96	                throw new IllegalArgumentException("sheetIndex out of bounds: " + sheetIndex
97	                        + ", total sheets: " + sourceWorkbook.getNumberOfSheets());
98	            }
99	
100	            Sheet sourceSheet = sourceWorkbook.getSheetAt(sheetIndex);
101	            appendSheet(sourceFilePath, targetFilePath, sourceSheet.getSheetName(), endRowIndex);
102	        }
103	    }
104	
105	    /**
106	     * Copies an entire sheet from source file to target file as-is.
107	     * Preserves all styles, column widths, merged regions, and formulas.
108	     * Unlike appendSheet which copies rows 0 to endRowIndex, this copies the entire sheet.
109	     *
110	     * @param sourceFilePath source Excel file path
111	     * @param targetFilePath target Excel file path (creates if not exists)
112	     * @param sheetName      sheet name to copy entirely
113	     */
114	    public static void copyEntireSheet(String sourceFilePath, String targetFilePath,
115	                                       String sheetName) throws IOException {
116	        try (FileInputStream srcFis = new FileInputStream(sourceFilePath);
117	             Workbook sourceWorkbook = WorkbookFactory.create(srcFis)) {
118	
119	            Sheet sourceSheet = sourceWorkbook.getSheet(sheetName);
120	            if (sourceSheet == null) {
121	                throw new IllegalArgumentException("Sheet not found: " + sheetName
122	                        + ", available sheets: " + getSheetNames(sourceWorkbook));
123	            }
124	
125	            Workbook targetWorkbook = loadOrCreate(targetFilePath);
126	
127	            if (targetWorkbook.getSheet(sheetName) != null) {
128	                targetWorkbook.close();
129	                throw new IllegalArgumentException("Target file already has sheet: " + sheetName);
130	            }
131	
132	            copySheetRows(sourceSheet, targetWorkbook, sheetName, sourceSheet.getLastRowNum());
133	
134	            try (FileOutputStream fos = new FileOutputStream(targetFilePath)) {
135	                targetWorkbook.write(fos);
136	            }
137	            targetWorkbook.close();
138	
139	            logger.debug("Entire sheet copied | sheet={}, rows=0-{}, target={}",
140	                    sheetName, sourceSheet.getLastRowNum(), targetFilePath);
141	        }
142	    }
143	
144	    /**
145	     * Appends data rows to an existing sheet in target file.
146	     *
147	     * @param orgFilePath   source file path (for getting style template)
148	     * @param targetFilePath target file path
149	     * @param sheetName     target sheet name
150	     * @param startRowIndex row index to start writing (typically header index)
151	     * @param rows          data rows to append
152	     */
153	    public static void appendDataRowsByPoi(
154	            String orgFilePath,
155	            String targetFilePath,
156	                                     String sheetName,
157	                                     int startRowIndex,
158	                                     List<Map<Integer, Object>> rows) throws IOException {
159	        // Get style template row from source file
160	        Row templateRow = null;
161	        try (FileInputStream srcFis = new FileInputStream(orgFilePath);
162	             Workbook srcWb = WorkbookFactory.create(srcFis)) {
163	            Sheet srcSheet = srcWb.getSheet(sheetName);
164	            if (srcSheet != null) {
165	                templateRow = srcSheet.getRow(startRowIndex);
166	            }
167	        }
168	
169	        // Open target file for appending
170	        File file = new File(targetFilePath);
171	        Workbook workbook;
172	        try (FileInputStream fis = new FileInputStream(file)) {
173	            workbook = WorkbookFactory.create(fis);
174	        }
175	        try {
176	
177	        Sheet sheet = workbook.getSheet(sheetName);
178	        Map<Integer, CellStyle> styleCache = new HashMap<>();
179	        final Row finalTemplateRow = templateRow;
180	
181	        int rowIdx = startRowIndex;
182	        for (Map<Integer, Object> rowData : rows) {
183	            Row row = sheet.createRow(rowIdx++);
184	            rowData.forEach((colIdx, value) -> {
185	                Cell cell = row.createCell(colIdx);
186	
187	                if (finalTemplateRow != null) {
188	                    Cell templateCell = finalTemplateRow.getCell(colIdx);
189	                    if (templateCell != null) {
190	                        CellStyle style = styleCache.computeIfAbsent(colIdx, k -> {
191	                            CellStyle newStyle = workbook.createCellStyle();
192	                            newStyle.cloneStyleFrom(templateCell.getCellStyle());
193	                            return newStyle;
194	                        });
195	                        cell.setCellStyle(style);
196	                    }
197	                }
198	
199	                if (value instanceof Number) {
200	                    cell.setCellValue(((Number) value).doubleValue());
201	                } else if (value instanceof Boolean) {
202	                    cell.setCellValue((Boolean) value);
203	                } else if (value != null) {
204	                    cell.setCellValue(value.toString());
205	                }
206	            });
207	        }
208	
209	        try (FileOutputStream fos = new FileOutputStream(file)) {
210	                workbook.write(fos);
211	            }
212	        } finally {
213	            workbook.close();
214	        }
215	    }
216	
217	    /**
218	     * Normalizes the input value by trimming whitespace, or returns "INVALID" if the value
219	     * is null, empty, or matches a known invalid data marker.
220	     *
221	     * @param val the input value to validate
222	     * @return the trimmed string if valid, or "INVALID" if null/empty/invalid marker
223	     */
224	    public static String normalizeOrInvalid(Object val){
225	        if (val == null) return "INVALID";
226	        String str = val.toString().trim();
227	        if (str.isEmpty() || INVALID_VALUES.contains(str.toUpperCase())) {
228	            return "INVALID";
229	        }
230	        return str;
231	    }
232	
233	    // ==================== Private Helper Methods ====================
234	
235	    /**
236	     * Loads existing workbook or creates new one if file doesn't exist.
237	     */
238	    private static Workbook loadOrCreate(String targetFilePath) throws IOException {
239	        File file = new File(targetFilePath);
240	        if (file.exists() && file.length() > 0) {
241	            try (FileInputStream fis = new FileInputStream(file)) {
242	                return WorkbookFactory.create(fis);
243	            }
244	        }
245	        return new XSSFWorkbook();
246	    }
247	
248	    /**
249	     * Copies rows 0 to endRowIndex from sourceSheet to a new sheet in targetWorkbook.
250	     */
251	    private static void copySheetRows(Sheet sourceSheet, Workbook targetWorkbook,
252	                                      String targetSheetName, int endRowIndex) {
253	        Sheet targetSheet = targetWorkbook.createSheet(targetSheetName);
254	        copyColumnWidths(sourceSheet, targetSheet);
255	        targetSheet.setDefaultRowHeight(sourceSheet.getDefaultRowHeight());
256	
257	        Map<Integer, CellStyle> styleCache = new HashMap<>();
258	        int actualEnd = Math.min(endRowIndex, sourceSheet.getLastRowNum());
259	
260	        for (int rowIdx = 0; rowIdx <= actualEnd; rowIdx++) {
261	            Row srcRow = sourceSheet.getRow(rowIdx);
262	            if (srcRow == null) continue;
263	            Row dstRow = targetSheet.createRow(rowIdx);
264	            dstRow.setHeight(srcRow.getHeight());
265	            copyCells(srcRow, dstRow, targetWorkbook, styleCache);
266	        }
267	
268	        copyMergedRegions(sourceSheet, targetSheet, actualEnd);
269	    }
270	
271	    private static void copyCells(Row srcRow, Row dstRow,
272	                                  Workbook targetWb,
273	                                  Map<Integer, CellStyle> styleCache) {
274	        for (int col = srcRow.getFirstCellNum(); col < srcRow.getLastCellNum(); col++) {
275	            Cell src = srcRow.getCell(col);
276	            if (src == null) continue;
277	
278	            Cell dst = dstRow.createCell(col);
279	
280	            CellStyle style = styleCache.computeIfAbsent(
281	                    src.getCellStyle().hashCode(), k -> {
282	                        CellStyle s = targetWb.createCellStyle();
283	                        s.cloneStyleFrom(src.getCellStyle());
284	                        return s;
285	                    });
286	            dst.setCellStyle(style);
287	
288	            switch (src.getCellType()) {
289	                case STRING:
290	                    dst.setCellValue(src.getStringCellValue());
291	                    break;
292	                case NUMERIC:
293	                    if (DateUtil.isCellDateFormatted(src)) {
294	                        dst.setCellValue(src.getDateCellValue());
295	                    } else {
296	                        dst.setCellValue(src.getNumericCellValue());
297	                    }
298	                    break;
299	                case BOOLEAN:
300	                    dst.setCellValue(src.getBooleanCellValue());
301	                    break;
302	                case FORMULA:
303	                    dst.setCellFormula(src.getCellFormula());
304	                    break;
305	                case BLANK:
306	                    dst.setBlank();
307	                    break;
308	                case ERROR:
309	                    dst.setCellErrorValue(src.getErrorCellValue());
310	                    break;
311	                default:
312	                    break;
313	            }
314	        }
315	    }
316	
317	    private static void copyColumnWidths(Sheet src, Sheet dst) {
318	        int maxCol = 0;
319	        for (Row row : src) {
320	            if (row.getLastCellNum() > maxCol) maxCol = row.getLastCellNum();
321	        }
322	        dst.setDefaultColumnWidth(src.getDefaultColumnWidth());
323	        for (int i = 0; i < maxCol; i++) {
324	            dst.setColumnWidth(i, src.getColumnWidth(i));
325	        }
326	    }
327	
328	    private static void copyMergedRegions(Sheet src, Sheet dst, int endRow) {
329	        for (int i = 0; i < src.getNumMergedRegions(); i++) {
330	            CellRangeAddress region = src.getMergedRegion(i);
331	            if (region.getLastRow() <= endRow) {
332	                dst.addMergedRegion(region.copy());
333	            }
334	        }
335	    }
336	
337	    private static String getSheetNames(Workbook workbook) {
338	        StringBuilder sb = new StringBuilder("[");
339	        for (int i = 0; i < workbook.getNumberOfSheets(); i++) {
340	            if (i > 0) sb.append(", ");
341	            sb.append(workbook.getSheetName(i));
342	        }
343	        return sb.append("]").toString();
344	    }
345	}

1	package fan.summer.app;
2	
3	import fan.summer.plugin.PluginLoader;
4	import fan.summer.plugin.PluginRegistry;
5	import fan.summer.ui.MainWindow;
6	import fan.summer.Registrar.BuiltinToolRegistrar;
7	import javafx.application.Application;
8	import javafx.scene.Scene;
9	import javafx.scene.image.Image;
10	import javafx.scene.paint.Color;
11	import javafx.stage.Stage;
12	import javafx.stage.StageStyle;
13	
14	import java.nio.file.Path;
15	import java.nio.file.Paths;
16	
17	/**
18	 * Application entry point.
19	 * Startup sequence:
20	 *   1. Determine plugins/ directory
21	 *   2. Create PluginLoader + PluginRegistry
22	 *   3. Register built-in tools
23	 *   4. Build MainWindow and display
24	 *   5. Start PluginLoader (scan JARs + start file watcher)
25	 */
26	public class SwissKitJApp extends Application {
27	
28	    private MainWindow mainWindow;
29	
30	    @Override
31	    public void start(Stage stage) throws Exception {
32	
33	        // ── Plugin directory (prefer JAR sibling, fallback to working directory during dev) ──
34	        Path pluginsDir = resolvePluginsDir();
35	
36	        // ── Plugin system ──────────────────────────────────────
37	        PluginLoader   loader   = new PluginLoader(pluginsDir);
38	        PluginRegistry registry = new PluginRegistry(loader);
39	
40	        // ── Register built-in tools ──────────────────────────────
41	        BuiltinToolRegistrar.register(loader, registry);
42	
43	        // ── Main window ────────────────────────────────────────
44	        mainWindow = new MainWindow(stage, loader, registry);
45	
46	        // Transparent scene (for rounded window to display correctly)
47	        Scene scene = new Scene(mainWindow, 960, 620);
48	        scene.setFill(Color.TRANSPARENT);
49	        scene.getStylesheets().add(
50	            getClass().getResource("/css/glass.css").toExternalForm()
51	        );
52	
53	        // App icon (shown in Dock / taskbar)
54	        var iconUrl = getClass().getResource("/icon.png");
55	        if (iconUrl != null) {
56	            stage.getIcons().add(new Image(iconUrl.toExternalForm()));
57	        }
58	
59	        // Undecorated window (custom titlebar via TitleBar)
60	        stage.initStyle(StageStyle.TRANSPARENT);
61	        stage.setTitle("SwissKitJ");
62	        stage.setScene(scene);
63	        stage.setMinWidth(800);
64	        stage.setMinHeight(520);
65	        stage.show();
66	
67	        // ── Start plugin loading (after UI is displayed) ────────
68	        loader.start();
69	    }
70	
71	    @Override
72	    public void stop() {
73	        if (mainWindow != null) mainWindow.shutdown();
74	    }
75	
76	    // ── Helper: locate plugins directory ───────────────────────────
77	
78	    private Path resolvePluginsDir() {
79	        // Try JAR sibling directory
80	        try {
81	            Path jar = Paths.get(
82	                SwissKitJApp.class.getProtectionDomain()
83	                    .getCodeSource().getLocation().toURI()
84	            );
85	            Path candidate = jar.getParent().resolve("plugins");
86	            if (candidate.toFile().isDirectory()) return candidate;
87	        } catch (Exception ignored) {}
88	
89	        // Dev mode: plugins/ under working directory
90	        return Paths.get("plugins");
91	    }
92	
93	    public static void main(String[] args) {
94	        launch(args);
95	    }
96	}

1	package fan.summer.buildintool.excelsplitter;
2	
3	import org.apache.poi.ss.usermodel.*;
4	import org.apache.poi.xssf.usermodel.XSSFWorkbook;
5	
6	import java.io.FileOutputStream;
7	import java.nio.file.*;
8	import java.util.*;
9	import java.util.function.BiConsumer;
10	
11	/**
12	 * Excel split core logic.
13	 * Does not depend on JavaFX, can be safely called in background threads.
14	 *
15	 * Progress callback: BiConsumer<current progress (0~1), status description>
16	 */
17	public class ExcelSplitter {
18	
19	    public record SplitResult(int fileCount, List<Path> outputFiles) {}
20	
21	    private final SplitConfig           config;
22	    private final BiConsumer<Double, String> progress;
23	
24	    public ExcelSplitter(SplitConfig config, BiConsumer<Double, String> progress) {
25	        this.config   = config;
26	        this.progress = progress;
27	    }
28	
29	    public SplitResult split() throws Exception {
30	        progress.accept(0.0, "Reading file…");
31	
32	        try (Workbook src = WorkbookFactory.create(config.sourceFile.toFile(), null, true)) {
33	            return switch (config.mode) {
34	                case BY_SHEET      -> splitBySheet(src);
35	                case BY_COLUMN     -> splitByColumn(src);
36	                case BY_ROW_COUNT  -> splitByRowCount(src);
37	            };
38	        }
39	    }
40	
41	    // ── Split by sheet ─────────────────────────────────────
42	
43	    private SplitResult splitBySheet(Workbook src) throws Exception {
44	        List<String> targets = config.selectedSheets != null
45	            ? config.selectedSheets
46	            : config.sheetNames;
47	
48	        List<Path> outputs = new ArrayList<>();
49	        for (int i = 0; i < targets.size(); i++) {
50	            String name = targets.get(i);
51	            progress.accept((double) i / targets.size(), "Processing sheet：" + name);
52	
53	            Sheet sheet = src.getSheet(name);
54	            if (sheet == null) continue;
55	
56	            Path out = outputPath(sanitize(name));
57	            try (Workbook wb = new XSSFWorkbook();
58	                 FileOutputStream fos = new FileOutputStream(out.toFile())) {
59	                copySheet(src, sheet, wb);
60	                wb.write(fos);
61	            }
62	            outputs.add(out);
63	        }
64	        progress.accept(1.0, "Done");
65	        return new SplitResult(outputs.size(), outputs);
66	    }
67	
68	    // ── Split by column value ────────────────────────────────────────
69	
70	    private SplitResult splitByColumn(Workbook src) throws Exception {
71	        Sheet sheet = src.getSheetAt(0);
72	        Row header  = config.keepHeader ? sheet.getRow(sheet.getFirstRowNum()) : null;
73	        int  colIdx = config.splitColumnIndex;
74	
75	        // Group rows by column value
76	        Map<String, List<Row>> groups = new LinkedHashMap<>();
77	        for (int r = sheet.getFirstRowNum() + (config.keepHeader ? 1 : 0);
78	             r <= sheet.getLastRowNum(); r++) {
79	            Row row = sheet.getRow(r);
80	            if (row == null) continue;
81	            String key = cellValue(row.getCell(colIdx));
82	            groups.computeIfAbsent(key, k -> new ArrayList<>()).add(row);
83	        }
84	
85	        List<Path> outputs = new ArrayList<>();
86	        int i = 0;
87	        for (Map.Entry<String, List<Row>> entry : groups.entrySet()) {
88	            progress.accept((double) i / groups.size(), "Writing：" + entry.getKey());
89	            Path out = outputPath(sanitize(entry.getKey()));
90	            writeRows(src, sheet, header, entry.getValue(), out);
91	            outputs.add(out);
92	            i++;
93	        }
94	        progress.accept(1.0, "Done");
95	        return new SplitResult(outputs.size(), outputs);
96	    }
97	
98	    // ── Split by row count ────────────────────────────────────────
99	
100	    private SplitResult splitByRowCount(Workbook src) throws Exception {
101	        Sheet sheet   = src.getSheetAt(0);
102	        Row   header  = config.keepHeader ? sheet.getRow(sheet.getFirstRowNum()) : null;
103	        int   start   = sheet.getFirstRowNum() + (config.keepHeader ? 1 : 0);
104	        int   total   = sheet.getLastRowNum() - start + 1;
105	        int   batchSz = config.rowsPerFile;
106	
107	        List<Path> outputs = new ArrayList<>();
108	        int part = 1;
109	        for (int r = start; r <= sheet.getLastRowNum(); r += batchSz) {
110	            progress.accept((double)(r - start) / total, "Writing part " + part + "…");
111	            List<Row> batch = new ArrayList<>();
112	            for (int rr = r; rr < r + batchSz && rr <= sheet.getLastRowNum(); rr++) {
113	                Row row = sheet.getRow(rr);
114	                if (row != null) batch.add(row);
115	            }
116	            Path out = outputPath("part_" + String.format("%03d", part));
117	            writeRows(src, sheet, header, batch, out);
118	            outputs.add(out);
119	            part++;
120	        }
121	        progress.accept(1.0, "Done");
122	        return new SplitResult(outputs.size(), outputs);
123	    }
124	
125	    // ── Helper: write rows ─────────────────────────────────────
126	
127	    private void writeRows(Workbook src, Sheet srcSheet,
128	                           Row header, List<Row> rows, Path dest) throws Exception {
129	        try (Workbook wb = new XSSFWorkbook();
130	             FileOutputStream fos = new FileOutputStream(dest.toFile())) {
131	            Sheet out = wb.createSheet(srcSheet.getSheetName());
132	            int rowNum = 0;
133	            if (header != null) {
134	                copyRow(src, wb, header, out.createRow(rowNum++));
135	            }
136	            for (Row src_row : rows) {
137	                copyRow(src, wb, src_row, out.createRow(rowNum++));
138	            }
139	            // Auto column width (only first 50 columns to avoid performance issues)
140	            int cols = Math.min(srcSheet.getRow(srcSheet.getFirstRowNum()) != null
141	                ? srcSheet.getRow(srcSheet.getFirstRowNum()).getLastCellNum() : 10, 50);
142	            for (int c = 0; c < cols; c++) out.autoSizeColumn(c);
143	            wb.write(fos);
144	        }
145	    }
146	
147	    // ── Helper: sheet copy ─────────────────────────────────
148	
149	    private void copySheet(Workbook srcWb, Sheet src, Workbook destWb) {
150	        Sheet dest = destWb.createSheet(src.getSheetName());
151	        for (int r = src.getFirstRowNum(); r <= src.getLastRowNum(); r++) {
152	            Row srcRow = src.getRow(r);
153	            if (srcRow == null) continue;
154	            copyRow(srcWb, destWb, srcRow, dest.createRow(r));
155	        }
156	        // Column width
157	        int cols = src.getRow(src.getFirstRowNum()) != null
158	            ? src.getRow(src.getFirstRowNum()).getLastCellNum() : 0;
159	        for (int c = 0; c < Math.min(cols, 50); c++) dest.autoSizeColumn(c);
160	    }
161	
162	    private void copyRow(Workbook srcWb, Workbook destWb, Row src, Row dest) {
163	        dest.setHeight(src.getHeight());
164	        for (int c = src.getFirstCellNum(); c < src.getLastCellNum(); c++) {
165	            Cell srcCell  = src.getCell(c);
166	            Cell destCell = dest.createCell(c);
167	            if (srcCell == null) continue;
168	            copyCellValue(srcCell, destCell);
169	        }
170	    }
171	
172	    private void copyCellValue(Cell src, Cell dest) {
173	        switch (src.getCellType()) {
174	            case STRING  -> dest.setCellValue(src.getStringCellValue());
175	            case NUMERIC -> {
176	                if (DateUtil.isCellDateFormatted(src))
177	                    dest.setCellValue(src.getDateCellValue());
178	                else
179	                    dest.setCellValue(src.getNumericCellValue());
180	            }
181	            case BOOLEAN -> dest.setCellValue(src.getBooleanCellValue());
182	            case FORMULA -> {
183	                switch (src.getCachedFormulaResultType()) {
184	                    case NUMERIC  -> dest.setCellValue(src.getNumericCellValue());
185	                    case STRING   -> dest.setCellValue(src.getStringCellValue());
186	                    case BOOLEAN  -> dest.setCellValue(src.getBooleanCellValue());
187	                    default       -> dest.setCellFormula(src.getCellFormula());
188	                }
189	            }
190	            case BLANK   -> dest.setBlank();
191	            default      -> dest.setCellValue(src.toString());
192	        }
193	    }
194	
195	    // ── Helper: utility methods ────────────────────────────────────
196	
197	    private String cellValue(Cell cell) {
198	        if (cell == null) return "(empty)";
199	        return switch (cell.getCellType()) {
200	            case STRING  -> cell.getStringCellValue().trim();
201	            case NUMERIC -> String.valueOf((long) cell.getNumericCellValue());
202	            case BOOLEAN -> String.valueOf(cell.getBooleanCellValue());
203	            default      -> cell.toString().trim();
204	        };
205	    }
206	
207	    /** Strip characters that are illegal in file names */
208	    private String sanitize(String name) {
209	        return name.replaceAll("[\\\\/:*?\"<>|]", "_").trim();
210	    }
211	
212	    private Path outputPath(String name) {
213	        String prefix = config.filePrefix.isBlank() ? "" : config.filePrefix + "_";
214	        return config.outputDir.resolve(prefix + name + ".xlsx");
215	    }
216	}
