473	            progressBar.setStyle("-fx-accent: #5b8cf7; -fx-background-radius: 3; -fx-background-color: rgba(255,255,255,0.08);");
474	
475	            progressLabel = new Label("Preparing...…");
476	            progressLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px;");
477	
478	            resultBox = new VBox(8);
479	            resultBox.setStyle("-fx-background-color: transparent;");
480	
481	            getChildren().addAll(title, progressBar, progressLabel, resultBox);
482	        }
483	
484	        void startSplit() {
485	            if (started) return;
486	            started = true;
487	            resultBox.getChildren().clear();
488	
489	            Task<ExcelSplitter.SplitResult> task = new Task<>() {
490	                @Override
491	                protected ExcelSplitter.SplitResult call() throws Exception {
492	                    ExcelSplitter splitter = new ExcelSplitter(config, (pct, msg) ->
493	                        Platform.runLater(() -> {
494	                            progressBar.setProgress(pct);
495	                            progressLabel.setText(msg);
496	                        })
497	                    );
498	                    return splitter.split();
499	                }
500	            };
501	
502	            task.setOnSucceeded(e -> showSuccess(task.getValue()));
503	            task.setOnFailed(e  -> showError(task.getException()));
504	
505	            Thread t = new Thread(task);
506	            t.setDaemon(true);
507	            t.start();
508	        }
509	
510	        private void showSuccess(ExcelSplitter.SplitResult result) {
511	            progressBar.setProgress(1.0);
512	            progressBar.setStyle(progressBar.getStyle().replace("#5b8cf7", "#4cd97b"));
513	            progressLabel.setText("✓ Split complete, output " + result.fileCount() + "  files");
514	
515	            resultBox.getChildren().add(subLabel("Output files"));
516	            for (Path p : result.outputFiles()) {
517	                HBox row = new HBox(10);
518	                row.setAlignment(Pos.CENTER_LEFT);
519	                row.setPadding(new Insets(8, 12, 8, 12));
520	                row.setStyle(
521	                    "-fx-background-color: rgba(76,217,123,0.06);" +
522	                    "-fx-border-color: rgba(76,217,123,0.15);" +
523	                    "-fx-border-width: 1; -fx-border-radius: 8; -fx-background-radius: 8;"
524	                );
525	
526	                Label icon = new Label("📄");
527	                Label name = new Label(p.getFileName().toString());
528	                name.setStyle("-fx-text-fill: rgba(255,255,255,0.85); -fx-font-size: 12px;" +
529	                              "-fx-font-family: 'SF Mono','Consolas',monospace;");
530	                HBox.setHgrow(name, Priority.ALWAYS);
531	
532	                Button open = new Button("Open folder");
533	                open.setStyle(
534	                    "-fx-background-color: transparent; -fx-border-color: rgba(76,217,123,0.4);" +
535	                    "-fx-border-width: 1; -fx-border-radius: 5; -fx-text-fill: #4cd97b;" +
536	                    "-fx-font-size: 11px; -fx-padding: 3 8 3 8; -fx-cursor: hand;"
537	                );
538	                open.setOnAction(e -> {
539	                    try {
540	                        java.awt.Desktop.getDesktop().open(p.getParent().toFile());
541	                    } catch (Exception ex) { /* Skip */ }
542	                });
543	
544	                row.getChildren().addAll(icon, name, open);
545	                resultBox.getChildren().add(row);
546	            }
547	        }
548	
549	        private void showError(Throwable err) {
550	            progressBar.setProgress(0);
551	            progressBar.setStyle(progressBar.getStyle().replace("#5b8cf7", "#f25c5c"));
552	            progressLabel.setText("❌ Split failed");
553	
554	            Label errLabel = new Label(err.getMessage());
555	            errLabel.setStyle(
556	                "-fx-text-fill: #f25c5c; -fx-font-size: 12px; -fx-wrap-text: true;" +
557	                "-fx-background-color: rgba(242,92,92,0.08); -fx-padding: 12;" +
558	                "-fx-background-radius: 8;"
559	            );
560	            errLabel.setWrapText(true);
561	            resultBox.getChildren().add(errLabel);
562	        }
563	    }
564	
565	    // ════════════════════════════════════════════════════
566	    // Shared UI tools
567	    // ════════════════════════════════════════════════════
568	
