1	package fan.summer.api.component;
2	
3	import javafx.animation.*;
4	import javafx.geometry.*;
5	import javafx.scene.Node;
6	import javafx.scene.control.*;
7	import javafx.scene.layout.*;
8	import javafx.scene.paint.Color;
9	import javafx.scene.shape.*;
10	import javafx.util.Duration;
11	
12	import java.util.ArrayList;
13	import java.util.List;
14	import java.util.function.BooleanSupplier;
15	
16	/**
17	 * Generic multi-step wizard container.
18	 *
19	 * Usage:
20	 *   wizard.addStep("Select file", node, () -> validate());
21	 *   wizard.addStep("Split mode",  node, () -> true);
22	 *   wizard.addStep("Run split",   node, () -> true);
23	 *   wizard.build();
24	 */
25	public class StepWizard extends BorderPane {
26	
27	    public interface StepChangeListener {
28	        void onStepChanged(int from, int to, int total);
29	    }
30	
31	    private record Step(String title, Node content, BooleanSupplier canProceed) {}
32	
33	    // ── State ─────────────────────────────────────────────
34	    private final List<Step>   steps       = new ArrayList<>();
35	    private int                current     = 0;
36	    private StepChangeListener stepListener;
37	
38	    // ── Fixed child nodes ─────────────────────────────────
39	    private HBox   stepIndicator;
40	    private StackPane contentPane;
41	    private Button prevBtn;
42	    private Button nextBtn;
43	    private Label  stepHint;
44	
45	    // ── Colour constants ──────────────────────────────────
46	    private static final String ACCENT     = "#5b8cf7";
47	    private static final String DONE_COLOR = "#4cd97b";
48	    private static final String IDLE_COLOR = "rgba(255,255,255,0.15)";
49	
50	    public StepWizard() {
51	        setStyle("-fx-background-color: transparent;");
52	    }
53	
54	    public void addStep(String title, Node content, BooleanSupplier canProceed) {
55	        steps.add(new Step(title, content, canProceed));
56	    }
57	
58	    public void setOnStepChanged(StepChangeListener l) { this.stepListener = l; }
59	
60	    /** Called once after all steps are added to build UI */
61	    public void build() {
62	        stepIndicator = buildStepIndicator();
63	        contentPane   = new StackPane();
64	        contentPane.setStyle("-fx-background-color: transparent;");
65	
66	        // Preload all content, opacity 0, only show current step
67	        for (Step s : steps) {
68	            s.content().setOpacity(0);
69	            s.content().setVisible(false);
70	            contentPane.getChildren().add(s.content());
71	        }
72	
73	        HBox footer = buildFooter();
74	
75	        VBox top = new VBox(stepIndicator);
76	        top.setPadding(new Insets(0, 0, 20, 0));
77	
78	        setTop(top);
79	        setCenter(contentPane);
80	        setBottom(footer);
81	        BorderPane.setMargin(footer, new Insets(16, 0, 0, 0));
82	
83	        // Show the first step
84	        showStep(0, -1);
85	    }
86	
87	    // ── Step indicator ────────────────────────────────────────
88	
89	    private HBox buildStepIndicator() {
90	        HBox row = new HBox();
91	        row.setAlignment(Pos.CENTER);
92	        row.setPadding(new Insets(0, 0, 4, 0));
93	
94	        for (int i = 0; i < steps.size(); i++) {
95	            // Circular step dot
96	            StackPane dot = makeDot(i);
97	            dot.setUserData(i); // Store index for refresh use
98	            row.getChildren().add(dot);
99	
100	            // Connector line (not added after last)
101	            if (i < steps.size() - 1) {
102	                Region line = new Region();
103	                line.setPrefHeight(2);
104	                line.setMinWidth(40);
105	                HBox.setHgrow(line, Priority.ALWAYS);
106	                line.setStyle("-fx-background-color: " + IDLE_COLOR + "; -fx-background-radius: 1;");
107	                line.setUserData("line_" + i);
108	                row.getChildren().add(line);
109	            }
110	        }
111	        return row;
112	    }
113	
114	    private StackPane makeDot(int idx) {
115	        Circle circle = new Circle(14);
116	        circle.setStrokeWidth(1.5);
117	
118	        Label num = new Label(String.valueOf(idx + 1));
119	        num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold;");
120	
121	        Label title = new Label(steps.get(idx).title());
122	        title.setStyle("-fx-font-size: 10px; -fx-text-fill: rgba(255,255,255,0.45);");
123	
124	        VBox labelBox = new VBox(2, num, title);
125	        labelBox.setAlignment(Pos.CENTER);
126	
127	        StackPane dot = new StackPane(circle, labelBox);
128	        dot.setPrefSize(28, 28);
129	        StackPane.setAlignment(title, Pos.BOTTOM_CENTER);
130	        StackPane.setMargin(title, new Insets(42, 0, 0, 0));
131	        return dot;
132	    }
133	
134	    /** Refresh all step dots and connector line styles */
135	    private void refreshIndicator() {
136	        int childIdx = 0;
137	        for (int i = 0; i < steps.size(); i++) {
138	            if (childIdx >= stepIndicator.getChildren().size()) break;
139	            StackPane dot = (StackPane) stepIndicator.getChildren().get(childIdx);
140	            Circle  circle = (Circle)  dot.getChildren().get(0);
141	            StackPane labelBox = (StackPane) dot.getChildren().get(1);
142	            Label   num    = (Label)   ((VBox) dot.getChildren().get(1)).getChildren().get(0);
143	            Label   title  = (Label)   ((VBox) dot.getChildren().get(1)).getChildren().get(1);
144	            childIdx++;
145	
146	            if (i < current) {
147	                // Done
148	                circle.setFill(Color.web(DONE_COLOR, 0.9));
149	                circle.setStroke(Color.web(DONE_COLOR));
150	                num.setText("✓");
151	                num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold; -fx-text-fill: #0d0e11;");
152	                title.setStyle("-fx-font-size: 10px; -fx-text-fill: " + DONE_COLOR + ";");
153	            } else if (i == current) {
154	                // Current step
155	                circle.setFill(Color.web(ACCENT, 0.9));
156	                circle.setStroke(Color.web(ACCENT));
157	                num.setText(String.valueOf(i + 1));
158	                num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold; -fx-text-fill: white;");
159	                title.setStyle("-fx-font-size: 10px; -fx-text-fill: " + ACCENT + "; -fx-font-weight: 500;");
160	
161	                // Pulse animation
162	                ScaleTransition pulse = new ScaleTransition(Duration.millis(600), dot);
163	                pulse.setFromX(1.0); pulse.setFromY(1.0);
164	                pulse.setToX(1.12); pulse.setToY(1.12);
165	                pulse.setAutoReverse(true); pulse.setCycleCount(2);
166	                pulse.play();
167	            } else {
168	                // Not yet reached
169	                circle.setFill(Color.web("rgba(255,255,255,0.06)"));
170	                circle.setStroke(Color.web(IDLE_COLOR));
171	                num.setText(String.valueOf(i + 1));
172	                num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold; -fx-text-fill: rgba(255,255,255,0.35);");
173	                title.setStyle("-fx-font-size: 10px; -fx-text-fill: rgba(255,255,255,0.35);");
174	            }
175	
176	            // Connector line
177	            if (i < steps.size() - 1 && childIdx < stepIndicator.getChildren().size()) {
178	                Region line = (Region) stepIndicator.getChildren().get(childIdx);
179	                line.setStyle("-fx-background-color: "
180	                    + (i < current ? DONE_COLOR : IDLE_COLOR)
181	                    + "; -fx-background-radius: 1;");
182	                childIdx++;
183	            }
184	        }
185	    }
186	
187	    // ── Footer buttons ──────────────────────────────────────────
188	
189	    private HBox buildFooter() {
190	        prevBtn  = footerBtn("← ← Back", false);
191	        nextBtn  = footerBtn("Next →", true);
192	        stepHint = new Label();
193	        stepHint.setStyle("-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 11px;");
194	
195	        prevBtn.setOnAction(e -> goTo(current - 1));
196	        nextBtn.setOnAction(e -> {
197	            Step s = steps.get(current);
198	            if (!s.canProceed().getAsBoolean()) {
199	                shakeButton(nextBtn);
200	                return;
201	            }
202	            if (current < steps.size() - 1) goTo(current + 1);
203	        });
204	
205	        Region spacer = new Region();
206	        HBox.setHgrow(spacer, Priority.ALWAYS);
207	
208	        HBox footer = new HBox(12, prevBtn, spacer, stepHint, nextBtn);
209	        footer.setAlignment(Pos.CENTER_LEFT);
210	        return footer;
211	    }
212	
213	    private Button footerBtn(String text, boolean primary) {
214	        Button btn = new Button(text);
215	        if (primary) {
216	            btn.setStyle(
217	                "-fx-background-color: #5b8cf7; -fx-text-fill: white;" +
218	                "-fx-font-size: 13px; -fx-font-weight: 500;" +
219	                "-fx-background-radius: 8; -fx-border-width: 0;" +
220	                "-fx-padding: 9 20 9 20; -fx-cursor: hand;"
221	            );
222	            btn.setOnMouseEntered(e -> btn.setStyle(btn.getStyle()
223	                .replace("#5b8cf7", "#4a7bf5")));
224	            btn.setOnMouseExited(e -> btn.setStyle(btn.getStyle()
225	                .replace("#4a7bf5", "#5b8cf7")));
226	        } else {
227	            btn.setStyle(
228	                "-fx-background-color: rgba(255,255,255,0.07);" +
229	                "-fx-border-color: rgba(255,255,255,0.12); -fx-border-width: 1;" +
230	                "-fx-text-fill: rgba(255,255,255,0.7); -fx-font-size: 13px;" +
231	                "-fx-background-radius: 8; -fx-border-radius: 8;" +
232	                "-fx-padding: 9 20 9 20; -fx-cursor: hand;"
233	            );
234	        }
235	        return btn;
236	    }
237	
238	    // ── Step transition ──────────────────────────────────────────
239	
240	    public void goTo(int idx) {
241	        if (idx < 0 || idx >= steps.size()) return;
242	        int from = current;
243	        current = idx;
244	        showStep(idx, from);
245	        if (stepListener != null) stepListener.onStepChanged(from, idx, steps.size());
246	    }
247	
248	    private void showStep(int idx, int from) {
249	        refreshIndicator();
250	        updateFooterState();
251	
252	        Node incoming = steps.get(idx).content();
253	        incoming.setVisible(true);
254	
255	        if (from < 0) {
256	            // Initial display, no animation needed
257	            incoming.setOpacity(1);
258	            return;
259	        }
260	
261	        // Determine slide direction
262	        double dir = idx > from ? 1 : -1;
263	
264	        // Hide old step
265	        Node outgoing = steps.get(from).content();
266	        TranslateTransition outTt = new TranslateTransition(Duration.millis(220), outgoing);
267	        outTt.setToX(-dir * 40);
268	        FadeTransition outFt = new FadeTransition(Duration.millis(220), outgoing);
269	        outFt.setToValue(0);
270	        ParallelTransition out = new ParallelTransition(outTt, outFt);
271	        out.setOnFinished(e -> {
272	            outgoing.setVisible(false);
273	            outgoing.setTranslateX(0);
274	        });
275	        out.play();
276	
277	        // Show new step
278	        incoming.setTranslateX(dir * 40);
279	        incoming.setOpacity(0);
280	        TranslateTransition inTt = new TranslateTransition(Duration.millis(260), incoming);
281	        inTt.setToX(0);
282	        inTt.setInterpolator(Interpolator.SPLINE(0.4, 0.0, 0.2, 1.0));
283	        FadeTransition inFt = new FadeTransition(Duration.millis(260), incoming);
284	        inFt.setToValue(1);
285	        new ParallelTransition(inTt, inFt).play();
286	    }
287	
288	    private void updateFooterState() {
289	        prevBtn.setDisable(current == 0);
290	        prevBtn.setOpacity(current == 0 ? 0.4 : 1.0);
291	
292	        boolean isLast = current == steps.size() - 1;
293	        nextBtn.setText(isLast ? "✓ Complete" : "Next →");
294	        stepHint.setText("Step " + (current + 1) + "  of " + steps.size() + "  steps");
295	    }
296	
297	    /** Shake feedback when button validation fails */
298	    private void shakeButton(Node node) {
299	        TranslateTransition shake = new TranslateTransition(Duration.millis(60), node);
300	        shake.setFromX(0); shake.setByX(8);
301	        shake.setAutoReverse(true); shake.setCycleCount(4);
302	        shake.play();
303	    }
304	
305	    // ── Public queries ──────────────────────────────────────────
306	
307	    public int  getCurrentStep()  { return current; }
308	    public int  getTotalSteps()   { return steps.size(); }
309	    public boolean isLastStep()   { return current == steps.size() - 1; }
310	}
